import r from"node:timers";import c from"timers";it("node:perf_hooks should be the same as perf_hooks",()=>{expect(r).toStrictEqual(c)});var{setTimeout:a}=r;it("should set timeout",async()=>{let e=Date.now();await new Promise(o=>{a(o,10)});let t=Date.now();expect(t-e>=10).toBeTruthy()});it("should set nested timeout",e=>{a(()=>{a(e,10)},10)});it("should clear timeout",async()=>{let e=Date.now(),t="";await new Promise(n=>{let s=a(()=>{t="not-cleared",n()},5);a(()=>{t="cleared",n()},10),clearTimeout(s)});let o=Date.now();expect(o-e>=10).toBeTruthy(),expect(t).toEqual("cleared")});it("should set interval",async()=>{let e=Date.now(),t=1;await new Promise(n=>{let s=setInterval(()=>{if(t>4)return clearInterval(s),n();t++},5)});let o=Date.now();expect(o-e>=10).toBeTruthy(),expect(t).toEqual(5)});it("should clear interval",async()=>{let e=Date.now(),t=1;await new Promise(n=>{let s=setInterval(()=>{if(t==2){clearInterval(s);return}t++},5);a(n,20)});let o=Date.now();expect(o-e>10).toBeTruthy(),expect(t).toEqual(2)});it("should accept any parameter to clear timeout",()=>{expect(()=>{clearTimeout(null),clearTimeout(""),clearTimeout(!0),clearTimeout({})}).not.toThrow()});it("should import timers",()=>{expect(a).toStrictEqual(globalThis.setTimeout)});it("delay is optional",async()=>{let e=Date.now();await new Promise(o=>{a(o)});let t=Date.now();expect(t-e>=0).toBeTruthy()});it("delay can be negative.",async()=>{let e=Date.now();await new Promise(o=>{a(o,-1)});let t=Date.now();expect(t-e>=0).toBeTruthy()});
